const response = $input.first().json || {};
const aliases = { 'UK': 'United Kingdom', 'USA': 'United States', 'HongKong': 'Hong Kong' };
const normalize = (c) => aliases[c] || c;
const countries = Array.isArray(response.countries) ? response.countries.map(normalize) : [];

const cityMap = {
  'United Kingdom': ['London', 'Manchester', 'Edinburgh'],
  'United States': ['New York, NY', 'Boston, MA', 'Los Angeles, CA'],
  'Canada': ['Toronto', 'Vancouver', 'Montreal'],
  'Australia': ['Sydney', 'Melbourne', 'Brisbane'],
  'Germany': ['Berlin', 'Munich', 'Hamburg'],
  'France': ['Paris', 'Lyon', 'Toulouse'],
  'Netherlands': ['Amsterdam', 'Rotterdam', 'Eindhoven'],
  'Ireland': ['Dublin', 'Cork', 'Galway'],
  'Spain': ['Madrid', 'Barcelona', 'Valencia'],
  'Italy': ['Milan', 'Rome', 'Bologna'],
  'Switzerland': ['Zurich', 'Lausanne', 'Geneva'],
  'Singapore': ['Singapore']
};

const selected = countries.filter((c) => cityMap[c]);
const finalCountries = selected.length ? selected : Object.keys(cityMap);
const items = [];

for (const country of finalCountries) {
  for (const city of cityMap[country]) {
    const citySlug = city.replace(/\s+/g, '-');
    items.push({
      json: {
        country,
        city,
        source_url: `https://www.numbeo.com/cost-of-living/in/${encodeURIComponent(citySlug)}?displayCurrency=INR`
      }
    });
  }
}

return items;

const rows = $input.all();
const listings = [];

const fallback = {
  'United Kingdom': 95000,
  'United States': 120000,
  'Canada': 78000,
  'Australia': 90000,
  'Germany': 68000,
  'France': 76000,
  'Netherlands': 88000,
  'Ireland': 93000,
  'Spain': 62000,
  'Italy': 64000,
  'Switzerland': 145000,
  'Singapore': 130000
};

for (const [idx, row] of rows.entries()) {
  const j = row.json || {};
  const country = j.country || 'Unknown';
  const city = j.city || country;
  const raw = (j.body || j.data || '').toString();
  const cleaned = raw.replace(/<script[\s\S]*?<\/script>/gi, ' ').replace(/<style[\s\S]*?<\/style>/gi, ' ').replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ');

  const cityCentre = cleaned.match(/Apartment.*City Centre[^0-9]*([0-9][0-9,]*)/i);
  const outsideCentre = cleaned.match(/Apartment.*Outside of Centre[^0-9]*([0-9][0-9,]*)/i);

  const cc = cityCentre ? Number(cityCentre[1].replace(/,/g, '')) : null;
  const oc = outsideCentre ? Number(outsideCentre[1].replace(/,/g, '')) : null;
  const base = Number.isFinite(cc) && cc > 0 ? cc : (Number.isFinite(oc) && oc > 0 ? oc : (fallback[country] || 80000));

  const variants = [
    { type: 'Student Dormitory', factor: 0.62, distance: 1.2, amenities: ['Wi-Fi', 'Laundry', 'Study Desk', 'Utilities Included'] },
    { type: 'Private Room in Shared House', factor: 0.78, distance: 2.0, amenities: ['Wi-Fi', 'Kitchen Access', 'Laundry'] },
    { type: 'Studio Apartment', factor: 1.0, distance: 2.8, amenities: ['Wi-Fi', 'Private Kitchen', 'Heating/Cooling'] }
  ];

  for (const [vIdx, v] of variants.entries()) {
    listings.push({
      id: `n8n_${country.toLowerCase().replace(/[^a-z0-9]+/g, '_')}_${city.toLowerCase().replace(/[^a-z0-9]+/g, '_')}_${vIdx + 1}_${idx + 1}`.slice(0, 120),
      title: `${v.type} in ${city}`.slice(0, 140),
      country,
      price_inr: Math.max(15000, Math.round(base * v.factor)),
      distance_km: v.distance,
      amenities: v.amenities,
      image_url: null,
      available_from: 'Monthly rolling',
      student_friendly: true
    });
  }
}

return [{ json: { listings: listings.slice(0, 2400) } }];
